'use client'
import React, { useState } from 'react'

// Logos embedded as base64 — bypasses Vercel file-serving issues
const LOGO_MEDCLOUD = "data:image/png;base64,"
const LOGO_COSENTUS = "data:image/png;base64,"

export default function LoginPage() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)

  async function handleLogin(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)
    setError('')
    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      })
      const data = await res.json()
      if (res.ok) {
        localStorage.setItem('cosentus_region', data.country)
        localStorage.setItem('cosentus_portal_type', data.portalType)
        localStorage.setItem('cosentus_role', data.role)
        window.location.href = '/dashboard'
      } else {
        setError(data.error || 'Invalid email or password')
        setLoading(false)
      }
    } catch {
      setError('Network error — please try again')
      setLoading(false)
    }
  }

  const stats = [
    { value: '99.3%', label: 'Coding Accuracy' },
    { value: '25+',   label: 'Years in RCM' },
    { value: '1,000+', label: 'RCM Experts' },
    { value: '< 35',  label: 'Avg AR Days' },
  ]

  return (
    <div className="min-h-screen flex">

      {/* ═══════════════════════════════
          LEFT — Brand blue hero panel
      ═══════════════════════════════ */}
      <div
        className="hidden lg:flex w-[52%] shrink-0 flex-col justify-between relative overflow-hidden"
        style={{ background: '#00B5D6' }}
      >
        {/* Futuristic data grid — subtle horizontal scan lines */}
        <div
          className="pointer-events-none absolute inset-0 opacity-[0.04]"
          style={{
            backgroundImage:
              'repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(255,255,255,1) 3px, rgba(255,255,255,1) 4px)',
          }}
        />
        {/* Subtle vertical circuit traces */}
        <div className="pointer-events-none absolute inset-0 opacity-[0.06]"
          style={{
            backgroundImage:
              'linear-gradient(90deg, transparent 0%, transparent 20%, rgba(255,255,255,0.5) 20%, rgba(255,255,255,0.5) 20.2%, transparent 20.2%, transparent 45%, rgba(255,255,255,0.4) 45%, rgba(255,255,255,0.4) 45.15%, transparent 45.15%, transparent 72%, rgba(255,255,255,0.3) 72%, rgba(255,255,255,0.3) 72.1%, transparent 72.1%)',
          }}
        />

        {/* Top — AI status indicator */}
        <div className="relative z-10 px-16 pt-12">
          <div className="flex items-center gap-2.5">
            <span className="w-[7px] h-[7px] rounded-full bg-white shadow-[0_0_10px_rgba(255,255,255,0.6)] animate-pulse" />
            <span className="text-white/50 text-[11px] font-mono tracking-[0.15em] uppercase">
              AI Engine Online
            </span>
          </div>
        </div>

        {/* Main content */}
        <div className="relative z-10 px-16 pb-2">
          {/* Headline */}
          <div className="mb-14">
            <p className="text-white/50 text-[11px] font-mono tracking-[0.2em] uppercase mb-5">
              MedCloud by Cosentus
            </p>
            <h1
              className="text-white leading-[1.05] font-bold tracking-tight"
              style={{ fontSize: 'clamp(36px, 3.5vw, 52px)' }}
            >
              Revenue Cycle<br />Intelligence
            </h1>
            <p className="text-white/60 mt-5 text-[15px] leading-relaxed max-w-[340px]">
              AI-powered RCM built on 25+ years of healthcare expertise. Faster claims, fewer denials.
            </p>
          </div>

          {/* Stats — clean, no box, just numbers with thin separator lines */}
          <div className="grid grid-cols-4 gap-0">
            {stats.map(({ value, label }, i) => (
              <div
                key={label}
                className="flex flex-col gap-1.5 pr-6"
                style={{ borderLeft: i > 0 ? '1px solid rgba(255,255,255,0.15)' : 'none', paddingLeft: i > 0 ? '24px' : '0' }}
              >
                <span className="text-white font-bold text-[26px] leading-none font-mono tabular-nums tracking-tight">
                  {value}
                </span>
                <span className="text-white/40 text-[10px] font-medium tracking-[0.08em] uppercase">{label}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom — INC badge + version tag */}
        <div className="relative z-10 px-16 pb-10 flex items-end justify-between">
          <div className="flex items-center gap-3">
            <div className="w-7 h-7 rounded-md bg-white/10 flex items-center justify-center shrink-0">
              <span className="text-white/70 text-[10px] font-bold">Inc</span>
            </div>
            <p className="text-white/35 text-[11px] leading-snug">
              INC 5000 Fastest Growing · 3 consecutive years<br />
              Great Places to Work® Certified
            </p>
          </div>
          <span className="text-white/20 text-[10px] font-mono">v2.0</span>
        </div>
      </div>

      {/* ═══════════════════════════════
          RIGHT — Login form (white)
          Both logos live here
      ═══════════════════════════════ */}
      <div className="flex-1 flex flex-col bg-white">

        {/* TOP-RIGHT: MedCloud logo */}
        <div className="flex justify-end px-10 pt-9">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={LOGO_MEDCLOUD}
            alt="MedCloud"
            className="h-9 w-auto object-contain"
          />
        </div>

        {/* CENTER: Form — vertically + horizontally centered */}
        <div className="flex-1 flex items-center justify-center px-10 py-12">
          <div className="w-full max-w-[360px]">

            {/* Heading */}
            <div className="mb-9">
              <h2
                className="font-bold text-black tracking-tight leading-tight"
                style={{ fontSize: '28px', letterSpacing: '-0.02em' }}
              >
                Welcome back
              </h2>
              <p className="text-[14px] text-[#888] mt-2 font-normal">
                Sign in to your MedCloud account
              </p>
            </div>

            <form onSubmit={handleLogin} className="space-y-5">

              {/* Email */}
              <div className="space-y-1.5">
                <label className="text-[11px] font-semibold text-[#999] uppercase tracking-[0.08em] block">
                  Email Address
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  required
                  autoComplete="email"
                  autoFocus
                  placeholder="you@cosentus.com"
                  className="w-full rounded-[14px] px-4 py-[13px] text-[14px] text-black outline-none transition-all placeholder:text-[#C5C5C5]"
                  style={{
                    background: '#F7FBFD',
                    border: '1.5px solid #E2F0F5',
                    boxShadow: 'inset 0 1px 2px rgba(0,0,0,0.03)',
                  }}
                  onFocus={e => {
                    e.currentTarget.style.border = '1.5px solid #00B5D6'
                    e.currentTarget.style.boxShadow = '0 0 0 4px rgba(0,181,214,0.1), inset 0 1px 2px rgba(0,0,0,0.02)'
                    e.currentTarget.style.background = '#fff'
                  }}
                  onBlur={e => {
                    e.currentTarget.style.border = '1.5px solid #E2F0F5'
                    e.currentTarget.style.boxShadow = 'inset 0 1px 2px rgba(0,0,0,0.03)'
                    e.currentTarget.style.background = '#F7FBFD'
                  }}
                />
              </div>

              {/* Password */}
              <div className="space-y-1.5">
                <label className="text-[11px] font-semibold text-[#999] uppercase tracking-[0.08em] block">
                  Password
                </label>
                <input
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  required
                  autoComplete="current-password"
                  placeholder="••••••••••"
                  className="w-full rounded-[14px] px-4 py-[13px] text-[14px] text-black outline-none transition-all placeholder:text-[#C5C5C5]"
                  style={{
                    background: '#F7FBFD',
                    border: '1.5px solid #E2F0F5',
                    boxShadow: 'inset 0 1px 2px rgba(0,0,0,0.03)',
                  }}
                  onFocus={e => {
                    e.currentTarget.style.border = '1.5px solid #00B5D6'
                    e.currentTarget.style.boxShadow = '0 0 0 4px rgba(0,181,214,0.1), inset 0 1px 2px rgba(0,0,0,0.02)'
                    e.currentTarget.style.background = '#fff'
                  }}
                  onBlur={e => {
                    e.currentTarget.style.border = '1.5px solid #E2F0F5'
                    e.currentTarget.style.boxShadow = 'inset 0 1px 2px rgba(0,0,0,0.03)'
                    e.currentTarget.style.background = '#F7FBFD'
                  }}
                />
              </div>

              {/* Error */}
              {error && (
                <div className="text-[13px] text-red-600 bg-red-50 border border-red-100 rounded-[12px] px-4 py-3">
                  {error}
                </div>
              )}

              {/* Sign In button */}
              <button
                type="submit"
                disabled={loading}
                className="w-full text-white rounded-[14px] py-[14px] text-[14px] font-semibold transition-all disabled:opacity-50 active:scale-[0.98]"
                style={{
                  background: loading ? '#00B5D6' : 'linear-gradient(180deg, #17C2E0 0%, #00B5D6 100%)',
                  boxShadow: '0 1px 2px rgba(0,181,214,0.2), 0 4px 12px rgba(0,181,214,0.25)',
                  letterSpacing: '0.01em',
                }}
                onMouseEnter={e => {
                  if (!loading) (e.currentTarget.style.boxShadow = '0 1px 2px rgba(0,181,214,0.25), 0 6px 20px rgba(0,181,214,0.35)')
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.boxShadow = '0 1px 2px rgba(0,181,214,0.2), 0 4px 12px rgba(0,181,214,0.25)'
                }}
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-2">
                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Signing in…
                  </span>
                ) : 'Sign In'}
              </button>
            </form>
          </div>
        </div>

        {/* BOTTOM-RIGHT: A Cosentus Division */}
        <div className="flex justify-end px-10 pb-9">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={LOGO_COSENTUS}
            alt="A Cosentus Division"
            className="h-[13px] w-auto object-contain opacity-55"
          />
        </div>
      </div>
    </div>
  )
}
